29	/// Fact-name prefixes reserved for the diff-mode translation (observed in the
30	/// "Reserved prefixes" check, diff mode only).
31	const RESERVED_PREFIXES: &[&str] = &["DiffIntr", "DiffProto"];
32	
33	/// Word-fill width used by the oracle's pretty-printer for the wrapped
34	/// "Reserved prefixes" header (measured empirically: a line breaks before the
35	/// next word once it would exceed column 69).
36	const FILL_WIDTH: usize = 69;
37	
38	/// Reserved fact names (used as protocol facts -> "Reserved names").
39	const RESERVED_FACTS: &[&str] = &["K", "KU", "KD"];
40	/// Special I/O facts handled by the special-fact / Fr checks.
41	const SPECIAL_FACTS: &[&str] = &["In", "Out", "Fr"];
