43	fn is_reserved(name: &str) -> bool {
44	    RESERVED_FACTS.contains(&name)
45	}
46	fn is_special(name: &str) -> bool {
47	    SPECIAL_FACTS.contains(&name)
48	}
49	fn is_builtin_factname(name: &str) -> bool {
50	    is_reserved(name) || is_special(name)
51	}
