57	/// The protocol rules of a theory (excludes intruder rules).
58	pub fn protocol_rules(thy: &Theory) -> Vec<&Rule> {
59	    thy.items
60	        .iter()
61	        .filter_map(|it| match it {
62	            TheoryItem::Rule(r) => Some(r),
63	            _ => None,
64	        })
65	        .collect()
66	}
