68	fn collect_term_vars(t: &Term, out: &mut Vec<VarSpec>) {
69	    match t {
70	        Term::Var(v) => out.push(v.clone()),
71	        Term::App(_, args) | Term::Pair(args) => {
72	            for a in args {
73	                collect_term_vars(a, out);
74	            }
75	        }
76	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
77	            collect_term_vars(a, out);
78	            collect_term_vars(b, out);
79	        }
80	        Term::PatMatch(inner) => collect_term_vars(inner, out),
81	        _ => {}
82	    }
83	}
84	
85	fn collect_fact_vars(f: &Fact, out: &mut Vec<VarSpec>) {
86	    for a in &f.args {
87	        collect_term_vars(a, out);
88	    }
89	}
90	
91	fn collect_facts_vars(fs: &[Fact], out: &mut Vec<VarSpec>) {
92	    for f in fs {
93	        collect_fact_vars(f, out);
94	    }
95	}
