134	/// Collect maximal multiplication (`*`) subterms of a term, rendered as the
135	/// oracle prints them. A product is maximal: its own operands are not
136	/// descended into.
137	fn collect_mult_terms(t: &Term, out: &mut Vec<String>) {
138	    if let Term::BinOp(BinOp::Mult, _, _) = t {
139	        out.push(pp_term(t));
140	        return;
141	    }
142	    match t {
143	        Term::App(_, args) | Term::Pair(args) => {
144	            for a in args {
145	                collect_mult_terms(a, out);
146	            }
147	        }
148	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
149	            collect_mult_terms(a, out);
150	            collect_mult_terms(b, out);
151	        }
152	        Term::PatMatch(inner) => collect_mult_terms(inner, out),
153	        _ => {}
154	    }
155	}
