157	/// Indent every line of a (possibly multi-line) block by `n` spaces.
158	fn indent_block(s: &str, n: usize) -> String {
159	    let pad = " ".repeat(n);
160	    s.lines()
161	        .map(|l| format!("{}{}", pad, l))
162	        .collect::<Vec<_>>()
163	        .join("\n")
164	}
