166	/// Word-fill (Wadler/Leijen `fillSep`) at the given `width` with a leading
167	/// `indent` of spaces on every line. A word is pushed onto the current line
168	/// while it fits (column + 1 + word <= width), otherwise a new line begins.
169	fn fill_words(words: &[String], indent: usize, width: usize) -> String {
170	    let pad = " ".repeat(indent);
171	    let mut lines: Vec<String> = Vec::new();
172	    let mut cur = String::new();
173	    let mut col = 0usize;
174	    for w in words {
175	        let wlen = w.chars().count();
176	        if cur.is_empty() {
177	            cur = format!("{}{}", pad, w);
178	            col = indent + wlen;
179	        } else if col + 1 + wlen <= width {
180	            cur.push(' ');
181	            cur.push_str(w);
182	            col += 1 + wlen;
183	        } else {
184	            lines.push(std::mem::take(&mut cur));
185	            cur = format!("{}{}", pad, w);
186	            col = indent + wlen;
187	        }
188	    }
189	    if !cur.is_empty() {
190	        lines.push(cur);
191	    }
192	    lines.join("\n")
193	}
