202	fn var_key(v: &VarSpec) -> (String, u64, i32) {
203	    (v.name.clone(), v.idx, sort_rank(v.sort))
204	}
205	
206	fn sort_rank(s: SortHint) -> i32 {
207	    match s {
208	        SortHint::Msg => 0,
209	        SortHint::Pub => 1,
210	        SortHint::Fresh => 2,
211	        SortHint::Node => 3,
212	        SortHint::Nat => 4,
213	        SortHint::Untagged => 5,
214	        SortHint::Suffix(_) => 6,
215	    }
216	}
217	
218	fn dedup_vars(mut vs: Vec<VarSpec>) -> Vec<VarSpec> {
219	    vs.sort_by_key(var_key);
220	    vs.dedup_by_key(|v| var_key(v));
221	    vs
222	}
