224	// ---------------------------------------------------------------------------
225	// 1. Unbound variables
226	// ---------------------------------------------------------------------------
227	pub fn unbound_variables(thy: &Theory) -> Vec<WfError> {
228	    let mut entries: Vec<String> = Vec::new();
229	    for r in protocol_rules(thy) {
230	        // Bound = variables in premises plus let-bound variables.
231	        let mut bound: Vec<VarSpec> = Vec::new();
232	        collect_facts_vars(&r.premises, &mut bound);
233	        for lb in &r.let_block {
234	            collect_term_vars(&lb.var, &mut bound);
235	        }
236	        let bound: std::collections::HashSet<(String, u64, i32)> =
237	            bound.iter().map(var_key).collect();
238	
239	        // Used = variables in actions, conclusions, embedded restrictions,
240	        // and the right-hand-sides of let bindings.
241	        let mut used: Vec<VarSpec> = Vec::new();
242	        collect_facts_vars(&r.actions, &mut used);
243	        collect_facts_vars(&r.conclusions, &mut used);
244	        for lb in &r.let_block {
245	            collect_term_vars(&lb.value, &mut used);
246	        }
247	
248	        let mut unbound: Vec<VarSpec> = used
249	            .into_iter()
250	            .filter(var_needs_binding)
251	            .filter(|v| !bound.contains(&var_key(v)))
252	            .collect();
253	        unbound = dedup_vars(unbound);
254	        // Report order: by base name then index.
255	        unbound.sort_by(|a, b| a.name.cmp(&b.name).then(a.idx.cmp(&b.idx)));
256	
257	        if !unbound.is_empty() {
258	            let names: Vec<String> = unbound.iter().map(pp_var).collect();
259	            entries.push(format!(
260	                "  rule `{}' has unbound variables: \n    {}",
261	                r.name,
262	                names.join(", ")
263	            ));
264	        }
265	    }
266	    if entries.is_empty() {
267	        vec![]
268	    } else {
269	        vec![WfError::new(T_UNBOUND, entries.join("\n  \n"))]
270	    }
271	}
