273	// ---------------------------------------------------------------------------
274	// 3. Variable with mismatching sorts or capitalization
275	// ---------------------------------------------------------------------------
276	pub fn mismatching_sorts(thy: &Theory) -> Vec<WfError> {
277	    let mut rule_entries: Vec<String> = Vec::new();
278	    for r in protocol_rules(thy) {
279	        let mut vars: Vec<VarSpec> = Vec::new();
280	        collect_facts_vars(&r.premises, &mut vars);
281	        collect_facts_vars(&r.actions, &mut vars);
282	        collect_facts_vars(&r.conclusions, &mut vars);
283	
284	        // Group by lowercased base name; a group with >1 distinct variant
285	        // (prefix+name, ignoring index) is a conflict.
286	        let mut groups: Vec<(String, Vec<String>)> = Vec::new(); // (lc key, variants)
287	        for v in &vars {
288	            let key = v.name.to_lowercase();
289	            let variant = variant_repr(v);
290	            match groups.iter_mut().find(|(k, _)| *k == key) {
291	                Some((_, variants)) => {
292	                    if !variants.contains(&variant) {
293	                        variants.push(variant);
294	                    }
295	                }
296	                None => groups.push((key, vec![variant])),
297	            }
298	        }
299	        let mut conflicts: Vec<Vec<String>> = groups
300	            .into_iter()
301	            .filter(|(_, vs)| vs.len() > 1)
302	            .map(|(_, mut vs)| {
303	                vs.sort();
304	                vs
305	            })
306	            .collect();
307	        if conflicts.is_empty() {
308	            continue;
309	        }
310	        // deterministic ordering of groups within a rule
311	        conflicts.sort();
312	        let mut body = format!("  rule `{}': ", r.name);
313	        for (i, variants) in conflicts.iter().enumerate() {
314	            body.push_str(&format!("\n    {}. {}", i + 1, variants.join(", ")));
315	        }
316	        rule_entries.push(body);
317	    }
318	    if rule_entries.is_empty() {
319	        return vec![];
320	    }
321	    let header = "Possible reasons:\n1. Identifiers are case sensitive, i.e.,'x' and 'X' are considered to be different.\n2. The same holds for sorts:, i.e., '$x', 'x', and '~x' are considered to be different.\n";
322	    let msg = format!("{}\n{}", header, rule_entries.join("\n  \n"));
323	    vec![WfError::new(T_SORTS, msg)]
324	}
