326	/// A variable's sort+name representation without the numeric index.
327	fn variant_repr(v: &VarSpec) -> String {
328	    let prefix = match v.sort {
329	        SortHint::Fresh => "~",
330	        SortHint::Pub => "$",
331	        SortHint::Nat => "%",
332	        SortHint::Node => "#",
333	        _ => "",
334	    };
335	    format!("{}{}", prefix, v.name)
336	}
