338	// ---------------------------------------------------------------------------
339	// 4. Reserved names
340	// ---------------------------------------------------------------------------
341	pub fn reserved_names(thy: &Theory) -> Vec<WfError> {
342	    let mut entries: Vec<String> = Vec::new();
343	    for r in protocol_rules(thy) {
344	        // On the left/right the reserved set is {K,KU,KD}; in the middle
345	        // (actions) the I/O facts In/Out/Fr are reserved too (observed z9/z11).
346	        for (facts, phrase, middle) in [
347	            (&r.premises, "left-hand-side", false),
348	            (&r.actions, "the middle", true),
349	            (&r.conclusions, "the right-hand-side", false),
350	        ] {
351	            let hits: Vec<&Fact> = facts
352	                .iter()
353	                .filter(|f| is_reserved(&f.name) || (middle && is_special(&f.name)))
354	                .collect();
355	            if hits.is_empty() {
356	                continue;
357	            }
358	            let rendered: Vec<String> = hits.iter().map(|f| pp_fact(f)).collect();
359	            entries.push(format!(
360	                "  Rule `{}' contains facts with reserved names on {}:\n    {}",
361	                r.name,
362	                phrase,
363	                rendered.join(", ")
364	            ));
365	        }
366	    }
367	    if entries.is_empty() {
368	        vec![]
369	    } else {
370	        vec![WfError::new(T_RESERVED, entries.join("\n  \n"))]
371	    }
372	}
