374	// ---------------------------------------------------------------------------
375	// 5. Fr facts must only use a fresh- or a msg-variable
376	// ---------------------------------------------------------------------------
377	pub fn fr_facts(thy: &Theory) -> Vec<WfError> {
378	    let mut entries: Vec<String> = Vec::new();
379	    for r in protocol_rules(thy) {
380	        for facts in [&r.premises, &r.conclusions] {
381	            for f in facts {
382	                if f.name != "Fr" {
383	                    continue;
384	                }
385	                let ok = f.args.len() == 1
386	                    && matches!(
387	                        &f.args[0],
388	                        Term::Var(v) if matches!(v.sort, SortHint::Fresh | SortHint::Msg | SortHint::Untagged)
389	                    );
390	                if !ok {
391	                    entries.push(format!("  rule `{}' fact: {}", r.name, pp_fact(f)));
392	                }
393	            }
394	        }
395	    }
396	    if entries.is_empty() {
397	        vec![]
398	    } else {
399	        vec![WfError::new(T_FR, entries.join("\n  \n"))]
400	    }
401	}
