403	// ---------------------------------------------------------------------------
404	// 6. Special facts (disallowed I/O facts in wrong position)
405	// ---------------------------------------------------------------------------
406	pub fn special_facts(thy: &Theory) -> Vec<WfError> {
407	    let mut entries: Vec<String> = Vec::new();
408	    for r in protocol_rules(thy) {
409	        // Premise side: `Out` is disallowed.
410	        let lhs: Vec<String> = r
411	            .premises
412	            .iter()
413	            .filter(|f| f.name == "Out")
414	            .map(|f| pp_fact(f))
415	            .collect();
416	        if !lhs.is_empty() {
417	            entries.push(format!(
418	                "  rule `{}' uses disallowed facts on left-hand-side:\n    {}",
419	                r.name,
420	                lhs.join(", ")
421	            ));
422	        }
423	        // Conclusion side: `In` and `Fr` are disallowed.
424	        let rhs: Vec<String> = r
425	            .conclusions
426	            .iter()
427	            .filter(|f| f.name == "In" || f.name == "Fr")
428	            .map(|f| pp_fact(f))
429	            .collect();
430	        if !rhs.is_empty() {
431	            entries.push(format!(
432	                "  rule `{}' uses disallowed facts on right-hand-side:\n    {}",
433	                r.name,
434	                rhs.join(", ")
435	            ));
436	        }
437	    }
438	    if entries.is_empty() {
439	        vec![]
440	    } else {
441	        vec![WfError::new(T_SPECIAL, entries.join("\n  \n"))]
442	    }
443	}
