449	struct FactUse {
450	    rule: String,
451	    arity: usize,
452	    persistent: bool,
453	    pp: String,
454	}
455	
456	/// Gather every fact occurrence in protocol rules (name -> uses), in source
457	/// order.
458	fn gather_fact_uses(thy: &Theory) -> Vec<(String, Vec<FactUse>)> {
459	    let mut map: Vec<(String, Vec<FactUse>)> = Vec::new();
460	    for r in protocol_rules(thy) {
461	        for facts in [&r.premises, &r.actions, &r.conclusions] {
462	            for f in facts {
463	                let entry = FactUse {
464	                    rule: r.name.clone(),
465	                    arity: f.args.len(),
466	                    persistent: f.persistent,
467	                    pp: pp_fact(f),
468	                };
469	                match map.iter_mut().find(|(n, _)| *n == f.name) {
470	                    Some((_, uses)) => uses.push(entry),
471	                    None => map.push((f.name.clone(), vec![entry])),
472	                }
473	            }
474	        }
475	    }
476	    map
477	}
