479	fn render_fact_blocks(conflicts: &[(String, Vec<String>)], intro1: &str, intro2: &str) -> String {
480	    // conflicts: (lowercased fact name, item lines) already ordered.
481	    let mut body = format!("{}\n{}\n  ", intro1, intro2);
482	    for (i, (lname, items)) in conflicts.iter().enumerate() {
483	        let block = format!("  Fact `{}':\n\n{}\n  ", lname, items.join("\n    \n"));
484	        if i == 0 {
485	            body.push_str("\n\n");
486	        } else {
487	            body.push('\n');
488	        }
489	        body.push_str(&block);
490	    }
491	    body
492	}
