494	pub fn fact_arity(thy: &Theory) -> Vec<WfError> {
495	    let uses = gather_fact_uses(thy);
496	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
497	    for (name, us) in &uses {
498	        let arities: std::collections::BTreeSet<usize> = us.iter().map(|u| u.arity).collect();
499	        if arities.len() < 2 {
500	            continue;
501	        }
502	        // one item per distinct (rule, arity), first pp kept, source order.
503	        let mut seen: Vec<(String, usize)> = Vec::new();
504	        let mut items: Vec<String> = Vec::new();
505	        for u in us {
506	            let k = (u.rule.clone(), u.arity);
507	            if seen.contains(&k) {
508	                continue;
509	            }
510	            seen.push(k);
511	            let n = items.len() + 1;
512	            items.push(format!(
513	                "    {}. Rule `{}', arity {}\n         {}",
514	                n, u.rule, u.arity, u.pp
515	            ));
516	        }
517	        conflicts.push((name.to_lowercase(), items));
518	    }
519	    if conflicts.is_empty() {
520	        return vec![];
521	    }
522	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
523	    let msg = render_fact_blocks(
524	        &conflicts,
525	        "Same fact is used with different arities, i.e., Fact('A','B') is different from Fact('A'). ",
526	        "Check the arguments of your facts.",
527	    );
528	    vec![WfError::new(T_ARITY, msg)]
529	}
