531	pub fn fact_multiplicity(thy: &Theory) -> Vec<WfError> {
532	    let uses = gather_fact_uses(thy);
533	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
534	    for (name, us) in &uses {
535	        let mults: std::collections::BTreeSet<bool> = us.iter().map(|u| u.persistent).collect();
536	        if mults.len() < 2 {
537	            continue;
538	        }
539	        let mut seen: Vec<(String, bool)> = Vec::new();
540	        let mut items: Vec<String> = Vec::new();
541	        for u in us {
542	            let k = (u.rule.clone(), u.persistent);
543	            if seen.contains(&k) {
544	                continue;
545	            }
546	            seen.push(k);
547	            let n = items.len() + 1;
548	            let m = if u.persistent { "Persistent" } else { "Linear" };
549	            items.push(format!(
550	                "    {}. Rule `{}', multiplicity (persistence) {}\n         {}",
551	                n, u.rule, m, u.pp
552	            ));
553	        }
554	        conflicts.push((name.to_lowercase(), items));
555	    }
556	    if conflicts.is_empty() {
557	        return vec![];
558	    }
559	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
560	    let msg = render_fact_blocks(
561	        &conflicts,
562	        "Same fact is used with different multiplicities, i.e., !Fact() (Persistent fact) exists along with Fact() (Linear) in your rules. ",
563	        "Check the multiplicity (persistence) of your facts.",
564	    );
565	    vec![WfError::new(T_MULT, msg)]
566	}
