571	
572	#[derive(Clone)]
573	struct FactId {
574	    name: String,
575	    arity: usize,
576	    persistent: bool,
577	    rule: String,
578	}
579	
580	impl FactId {
581	    fn ident(&self) -> (String, usize, bool) {
582	        (self.name.clone(), self.arity, self.persistent)
583	    }
584	    fn render(&self) -> String {
585	        format!(
586	            "in rule \"{}\":  factName `{}' arity: {} multiplicity: {}",
587	            self.rule,
588	            self.name,
589	            self.arity,
590	            if self.persistent { "Persistent" } else { "Linear" }
591	        )
592	    }
593	}
594	
595	pub fn fact_lhs_occur_no_rhs(thy: &Theory) -> Vec<WfError> {
596	    let mut lhs: Vec<FactId> = Vec::new();
597	    let mut rhs: Vec<FactId> = Vec::new();
598	    for r in protocol_rules(thy) {
599	        for f in &r.premises {
600	            if is_builtin_factname(&f.name) {
601	                continue;
602	            }
603	            lhs.push(FactId {
604	                name: f.name.clone(),
605	                arity: f.args.len(),
606	                persistent: f.persistent,
607	                rule: r.name.clone(),
608	            });
609	        }
610	        for f in &r.conclusions {
611	            if is_builtin_factname(&f.name) {
612	                continue;
613	            }
614	            rhs.push(FactId {
615	                name: f.name.clone(),
616	                arity: f.args.len(),
617	                persistent: f.persistent,
618	                rule: r.name.clone(),
619	            });
620	        }
621	    }
622	    let rhs_idents: std::collections::HashSet<(String, usize, bool)> =
623	        rhs.iter().map(|f| f.ident()).collect();
624	
625	    // LHS-only identities, first occurrence, in source order.
626	    let mut seen: Vec<(String, usize, bool)> = Vec::new();
627	    let mut items: Vec<String> = Vec::new();
628	    for f in &lhs {
629	        if rhs_idents.contains(&f.ident()) || seen.contains(&f.ident()) {
630	            continue;
631	        }
632	        seen.push(f.ident());
633	        let n = items.len() + 1;
634	        let mut line = format!("  {}. {}", n, f.render());
635	        if let Some(sugg) = nearest_rhs(&f.name, &rhs) {
636	            line.push_str(&format!(". Perhaps you want to use the fact {}", sugg.render()));
637	        }
638	        items.push(line);
639	    }
640	    if items.is_empty() {
641	        vec![]
642	    } else {
643	        vec![WfError::new(T_LHSRHS, items.join("\n  \n"))]
644	    }
645	}
646	
647	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
648	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
649	    let mut best: Option<(usize, &FactId)> = None;
650	    for f in rhs {
651	        let d = edit_distance(name, &f.name);
652	        match best {
653	            Some((bd, _)) if d >= bd => {}
654	            _ => best = Some((d, f)),
655	        }
656	    }
657	    match best {
658	        Some((d, f)) if d <= 3 => Some(f),
659	        _ => None,
660	    }
661	}
662	
663	fn edit_distance(a: &str, b: &str) -> usize {
664	    let a: Vec<char> = a.chars().collect();
665	    let b: Vec<char> = b.chars().collect();
666	    let mut prev: Vec<usize> = (0..=b.len()).collect();
667	    let mut cur = vec![0usize; b.len() + 1];
668	    for i in 1..=a.len() {
669	        cur[0] = i;
670	        for j in 1..=b.len() {
671	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
672	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
673	        }
674	        std::mem::swap(&mut prev, &mut cur);
675	    }
676	    prev[b.len()]
677	}
