680	// 2. Public constants with mismatching capitalization (public-names report)
681	// ---------------------------------------------------------------------------
682	
683	pub fn public_names_report(thy: &Theory) -> Vec<WfError> {
684	    let mut pairs: Vec<(String, String)> = Vec::new(); // (constName, ruleName)
685	    for r in protocol_rules(thy) {
686	        let mut names: Vec<String> = Vec::new();
687	        for facts in [&r.premises, &r.actions, &r.conclusions] {
688	            for f in facts {
689	                for a in &f.args {
690	                    collect_pub_lits(a, &mut names);
691	                }
692	            }
693	        }
694	        for n in names {
695	            let pair = (n, r.name.clone());
696	            if !pairs.contains(&pair) {
697	                pairs.push(pair);
698	            }
699	        }
700	    }
701	    public_names_report_from_pairs(pairs)
702	}
703	
704	pub fn public_names_report_from_pairs(pairs: Vec<(String, String)>) -> Vec<WfError> {
705	    // Group by lowercased constant name, preserving first-seen order.
706	    let mut groups: Vec<(String, Vec<(String, String)>)> = Vec::new();
707	    for (name, rule) in &pairs {
708	        let key = name.to_lowercase();
709	        match groups.iter_mut().find(|(k, _)| *k == key) {
710	            Some((_, v)) => v.push((name.clone(), rule.clone())),
711	            None => groups.push((key, vec![(name.clone(), rule.clone())])),
712	        }
713	    }
714	    let mut items: Vec<String> = Vec::new();
715	    for (_, occ) in &groups {
716	        let distinct: std::collections::BTreeSet<&String> = occ.iter().map(|(n, _)| n).collect();
717	        if distinct.len() < 2 {
718	            continue; // no capitalization conflict
719	        }
720	        // Group occurrences by rule, preserving first-seen rule order.
721	        let mut by_rule: Vec<(String, Vec<String>)> = Vec::new();
722	        for (n, rule) in occ {
723	            match by_rule.iter_mut().find(|(rr, _)| rr == rule) {
724	                Some((_, ns)) => {
725	                    if !ns.contains(n) {
726	                        ns.push(n.clone());
727	                    }
728	                }
729	                None => by_rule.push((rule.clone(), vec![n.clone()])),
730	            }
731	        }
732	        let locs: Vec<String> = by_rule
733	            .into_iter()
734	            .map(|(rule, mut ns)| {
735	                ns.sort();
736	                let quoted: Vec<String> = ns.iter().map(|n| format!("'{}'", n)).collect();
737	                format!("rule \"{}\":  name {}", rule, quoted.join(", "))
738	            })
739	            .collect();
740	        let n = items.len() + 1;
741	        items.push(format!("  {}. {}", n, locs.join(", ")));
742	    }
743	    if items.is_empty() {
744	        return vec![];
745	    }
746	    let header = "Identifiers are case-sensitive, mismatched capitalizations are considered as different, i.e., 'ID' is different from 'id'. Check the capitalization of your identifiers.";
747	    let msg = format!("{}\n\n{}", header, items.join("\n  \n"));
748	    vec![WfError::new(T_PUBNAMES, msg)]
749	}
