751	// ---------------------------------------------------------------------------
752	// 10. Formula terms (free variables in lemma / restriction formulas)
753	// ---------------------------------------------------------------------------
754	
755	const FORMULA_TERMS_HELP: &str = "  The only allowed terms are public constants and bound node and\n  message variables. If you encounter free message variables, then\n  you might have forgotten a #-prefix. Sort prefixes can only be\n  dropped where this is unambiguous. Moreover, reducible function\n  symbols are disallowed.";
756	
757	// Bound variables are matched by NAME only. The oracle treats a quantified
758	// message variable and its occurrences as the same variable even when the
759	// parsed AST tags them with different-but-compatible sorts (e.g. Msg vs the
760	// Untagged default, or a temporal written `@ i` vs a quantifier `#i`); matching
761	// on the full sort tag produces spurious "free variable" reports (observed on
762	// round2/exists_trace_reuse). See BEHAVIOR.md.
763	fn free_vars_formula(f: &Formula, bound: &mut Vec<String>, out: &mut Vec<VarSpec>) {
764	    match f {
765	        Formula::False | Formula::True => {}
766	        Formula::Atom(a) => {
767	            let mut vs = Vec::new();
768	            atom_vars(a, &mut vs);
769	            for v in vs {
770	                if !bound.contains(&v.name) {
771	                    out.push(v);
772	                }
773	            }
774	        }
775	        Formula::Not(g) => free_vars_formula(g, bound, out),
776	        Formula::And(a, b)
777	        | Formula::Or(a, b)
778	        | Formula::Implies(a, b)
779	        | Formula::Iff(a, b) => {
780	            free_vars_formula(a, bound, out);
781	            free_vars_formula(b, bound, out);
782	        }
783	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
784	            let added: Vec<String> = vs.iter().map(|v| v.name.clone()).collect();
785	            let n = added.len();
786	            bound.extend(added);
787	            free_vars_formula(g, bound, out);
788	            for _ in 0..n {
789	                bound.pop();
790	            }
791	        }
792	    }
793	}
794	
795	fn atom_vars(a: &Atom, out: &mut Vec<VarSpec>) {
796	    match a {
797	        Atom::Eq(x, y)
798	        | Atom::Less(x, y)
799	        | Atom::LessMset(x, y)
800	        | Atom::Subterm(x, y) => {
801	            collect_term_vars(x, out);
802	            collect_term_vars(y, out);
803	        }
804	        Atom::Action(f, t) => {
805	            collect_fact_vars(f, out);
806	            collect_term_vars(t, out);
807	        }
808	        Atom::Last(t) => collect_term_vars(t, out),
809	        Atom::Pred(f) => collect_fact_vars(f, out),
810	    }
811	}
812	
813	fn formula_terms_entry(entity: &str, name: &str, free: &[VarSpec]) -> String {
814	    let terms: Vec<String> = free.iter().map(|v| format!("`Free {}'", pp_var(v))).collect();
815	    let head = if terms.len() == 1 {
816	        format!(
817	            "  {} `{}' uses terms of the wrong form: {}",
818	            entity, name, terms[0]
819	        )
820	    } else {
821	        format!(
822	            "  {} `{}' uses terms of the wrong form:\n    {}",
823	            entity,
824	            name,
825	            terms.join(", ")
826	        )
827	    };
828	    format!("{}\n  \n{}", head, FORMULA_TERMS_HELP)
829	}
830	
831	pub fn formula_terms(thy: &Theory) -> Vec<WfError> {
832	    let mut entries: Vec<String> = Vec::new();
833	    for it in &thy.items {
834	        let (entity, name, formula) = match it {
835	            TheoryItem::Lemma(l) => ("Lemma", &l.name, &l.formula),
836	            TheoryItem::Restriction(r) | TheoryItem::LegacyAxiom(r) => {
837	                ("Restriction", &r.name, &r.formula)
838	            }
839	            _ => continue,
840	        };
841	        let mut bound = Vec::new();
842	        let mut free = Vec::new();
843	        free_vars_formula(formula, &mut bound, &mut free);
844	        let free = dedup_vars(free);
845	        if !free.is_empty() {
846	            entries.push(formula_terms_entry(entity, name, &free));
847	        }
848	    }
849	    if entries.is_empty() {
850	        vec![]
851	    } else {
852	        vec![WfError::new(T_FORMULA_TERMS, entries.join("\n"))]
853	    }
854	}
