857	// 11. Formula guardedness (best-effort; single-line formula printer)
858	// ---------------------------------------------------------------------------
859	
860	pub fn formula_guardedness(thy: &Theory) -> Vec<WfError> {
861	    let mut entries: Vec<String> = Vec::new();
862	    for it in &thy.items {
863	        let (name, formula) = match it {
864	            TheoryItem::Lemma(l) => (&l.name, &l.formula),
865	            _ => continue,
866	        };
867	        if let Some((unguarded, sub)) = find_unguarded(formula) {
868	            let vars: Vec<String> = unguarded.iter().map(|v| format!("'{}'", pp_var(v))).collect();
869	            let pp_sub = crate::formula::pp_formula(&sub);
870	            let pp_whole = crate::formula::pp_formula(formula);
871	            entries.push(format!(
872	                "  Lemma `{}' cannot be converted to a guarded formula:\n    unguarded variable(s) {} in the subformula\n      \"{}\"\n    in the formula\n      \"{}\"",
873	                name,
874	                vars.join(", "),
875	                pp_sub,
876	                pp_whole
877	            ));
878	        }
879	    }
880	    if entries.is_empty() {
881	        vec![]
882	    } else {
883	        vec![WfError::new(T_GUARD, entries.join("\n"))]
884	    }
885	}
886	
887	/// Variables appearing in any Action or Pred atom anywhere in `f` (the guard
888	/// positions). Used as a permissive over-approximation of "guarded".
889	fn guard_vars(f: &Formula, out: &mut Vec<VarSpec>) {
890	    match f {
891	        Formula::Atom(Atom::Action(fact, t)) => {
892	            collect_fact_vars(fact, out);
893	            collect_term_vars(t, out);
894	        }
895	        Formula::Atom(Atom::Pred(fact)) => collect_fact_vars(fact, out),
896	        Formula::Atom(_) | Formula::True | Formula::False => {}
897	        Formula::Not(g) => guard_vars(g, out),
898	        Formula::And(a, b)
899	        | Formula::Or(a, b)
900	        | Formula::Implies(a, b)
901	        | Formula::Iff(a, b) => {
902	            guard_vars(a, out);
903	            guard_vars(b, out);
904	        }
905	        Formula::Forall(_, g) | Formula::Exists(_, g) => guard_vars(g, out),
906	    }
907	}
908	
909	/// Returns the first quantifier whose bound variables are not all guarded,
910	/// together with that subformula.
911	fn find_unguarded(f: &Formula) -> Option<(Vec<VarSpec>, Formula)> {
912	    match f {
913	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
914	            let mut gv = Vec::new();
915	            guard_vars(g, &mut gv);
916	            // Match guard variables by name (see free_vars_formula rationale).
917	            let gset: std::collections::HashSet<String> =
918	                gv.iter().map(|v| v.name.clone()).collect();
919	            let unguarded: Vec<VarSpec> = vs
920	                .iter()
921	                .filter(|v| !gset.contains(&v.name))
922	                .cloned()
923	                .collect();
924	            if !unguarded.is_empty() {
925	                return Some((unguarded, f.clone()));
926	            }
927	            find_unguarded(g)
928	        }
929	        Formula::Not(g) => find_unguarded(g),
930	        Formula::And(a, b)
931	        | Formula::Or(a, b)
932	        | Formula::Implies(a, b)
933	        | Formula::Iff(a, b) => find_unguarded(a).or_else(|| find_unguarded(b)),
934	        _ => None,
935	    }
936	}
