959	
960	fn collect_nat_issues(t: &Term, out: &mut Vec<String>) {
961	    if let Term::BinOp(BinOp::NatPlus, _, _) = t {
962	        let term_pp = pp_term(t);
963	        let mut vs = Vec::new();
964	        collect_term_vars(t, &mut vs);
965	        for v in vs {
966	            if v.sort != SortHint::Nat {
967	                let entry = format!("  {} in term {} must be of sort nat", pp_var(&v), term_pp);
968	                if !out.contains(&entry) {
969	                    out.push(entry);
970	                }
971	            }
972	        }
973	    }
974	    // recurse
975	    match t {
976	        Term::App(_, args) | Term::Pair(args) => {
977	            for a in args {
978	                collect_nat_issues(a, out);
979	            }
980	        }
981	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
982	            collect_nat_issues(a, out);
983	            collect_nat_issues(b, out);
984	        }
985	        Term::PatMatch(inner) => collect_nat_issues(inner, out),
986	        _ => {}
987	    }
988	}
