993	
994	pub fn subterm_convergence(thy: &Theory) -> Vec<WfError> {
995	    let mut bad: Vec<String> = Vec::new();
996	    for it in &thy.items {
997	        if let TheoryItem::Equations { convergent, eqs } = it {
998	            if *convergent {
999	                continue; // user asserted convergence
1000	            }
1001	            for eq in eqs {
1002	                if !is_subterm(&eq.rhs, &eq.lhs) {
1003	                    bad.push(format!("    {} = {}", pp_term(&eq.lhs), pp_term(&eq.rhs)));
1004	                }
1005	            }
1006	        }
1007	    }
1008	    if bad.is_empty() {
1009	        return vec![];
1010	    }
1011	    let intro = "  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue ";
1012	    let manual = " For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ";
1013	    let msg = format!("{}\n\n{}\n   \n{}", intro, bad.join("\n"), manual);
1014	    vec![WfError::new(T_SUBTERM, msg)]
1015	}
