1017	/// Structural subterm test: does `small` occur as a subterm of `big`?
1018	fn is_subterm(small: &Term, big: &Term) -> bool {
1019	    if small == big {
1020	        return true;
1021	    }
1022	    match big {
1023	        Term::App(_, args) | Term::Pair(args) => args.iter().any(|a| is_subterm(small, a)),
1024	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1025	            is_subterm(small, a) || is_subterm(small, b)
1026	        }
1027	        Term::PatMatch(inner) => is_subterm(small, inner),
1028	        _ => false,
1029	    }
1030	}
