1066	// 5. Reserved prefixes (diff mode only)
1067	// ---------------------------------------------------------------------------
1068	// Fact names beginning with `DiffIntr`/`DiffProto` are reserved for the diff
1069	// translation. Only emitted for diff-mode theories (observed: silent otherwise).
1070	pub fn reserved_prefixes(thy: &Theory) -> Vec<WfError> {
1071	    if !thy.is_diff {
1072	        return vec![];
1073	    }
1074	    let mut entries: Vec<String> = Vec::new();
1075	    for r in protocol_rules(thy) {
1076	        // Order of collection: premises, actions, conclusions (probe rp_multi).
1077	        let mut hits: Vec<&Fact> = Vec::new();
1078	        for facts in [&r.premises, &r.actions, &r.conclusions] {
1079	            for f in facts {
1080	                if RESERVED_PREFIXES.iter().any(|p| f.name.starts_with(p)) {
1081	                    hits.push(f);
1082	                }
1083	            }
1084	        }
1085	        if hits.is_empty() {
1086	            continue;
1087	        }
1088	        let header = fill_words(&reserved_prefix_header_words(&r.name), 2, FILL_WIDTH);
1089	        let blocks: Vec<String> = hits
1090	            .iter()
1091	            .map(|f| {
1092	                let m = if f.persistent { "Persistent" } else { "Linear" };
1093	                format!(
1094	                    "    {}\n    (ProtoFact {} \"{}\" {},{},{})",
1095	                    pp_fact(f),
1096	                    m,
1097	                    f.name,
1098	                    f.args.len(),
1099	                    f.args.len(),
1100	                    m
1101	                )
1102	            })
1103	            .collect();
1104	        entries.push(format!("{}\n  \n{}", header, blocks.join("\n  \n")));
1105	    }
1106	    if entries.is_empty() {
1107	        vec![]
1108	    } else {
1109	        vec![WfError::new(T_RESERVED_PREFIX, entries.join("\n  \n"))]
1110	    }
1111	}
1112	
1113	fn reserved_prefix_header_words(rule: &str) -> Vec<String> {
1114	    [
1115	        "The",
1116	        "Rule",
1117	        &format!("`{}'", rule),
1118	        "contains",
1119	        "facts",
1120	        "with",
1121	        "reserved",
1122	        "prefixes",
1123	        "('DiffIntr',",
1124	        "'DiffProto')",
1125	        "inside",
1126	        "names:",
1127	    ]
1128	    .iter()
1129	    .map(|s| s.to_string())
1130	    .collect()
1131	}
1132	
1133	// ---------------------------------------------------------------------------
1134	// 11 & 12. Left rule / Right rule (diff mode only)
1135	// ---------------------------------------------------------------------------
1136	// A diff rule may carry explicit `left`/`right` projections. Each explicit
1137	// projection must equal the corresponding projection of the parent diff rule
1138	// (diff(a,b) -> a on the left, -> b on the right). When it differs, the rule is
1139	// "inconsistent". For a single rule the left projection is checked first and,
1140	// if inconsistent, the right is not reported (observed via probe diff_both).
1141	pub fn diff_left_right(thy: &Theory) -> Vec<WfError> {
1142	    if !thy.is_diff {
1143	        return vec![];
1144	    }
1145	    let mut left_entries: Vec<String> = Vec::new();
1146	    let mut right_entries: Vec<String> = Vec::new();
1147	    for r in protocol_rules(thy) {
1148	        if let Some((left, right)) = &r.left_right {
1149	            if !rule_matches_projection(r, left, true) {
1150	                left_entries.push(inconsistent_entry("left", left, r));
1151	            } else if !rule_matches_projection(r, right, false) {
1152	                right_entries.push(inconsistent_entry("right", right, r));
1153	            }
1154	        }
1155	    }
1156	    let mut out = Vec::new();
1157	    if !left_entries.is_empty() {
1158	        out.push(WfError::new(T_LEFT, left_entries.join("\n  \n")));
1159	    }
1160	    if !right_entries.is_empty() {
1161	        out.push(WfError::new(T_RIGHT, right_entries.join("\n  \n")));
1162	    }
1163	    out
1164	}
1165	
1166	fn inconsistent_entry(side: &str, explicit: &Rule, parent: &Rule) -> String {
1167	    format!(
1168	        "  Inconsistent {} rule\n{}\n  \n  w.r.t.\n  \n{}",
1169	        side,
1170	        indent_block(&pp_rule(explicit), 4),
1171	        indent_block(&pp_rule(parent), 4)
1172	    )
1173	}
1174	
1175	/// True iff the explicit rule's fact lists equal the parent rule's projection.
1176	fn rule_matches_projection(parent: &Rule, explicit: &Rule, left: bool) -> bool {
1177	    facts_pp(&project_facts(&parent.premises, left)) == facts_pp(&explicit.premises)
1178	        && facts_pp(&project_facts(&parent.actions, left)) == facts_pp(&explicit.actions)
1179	        && facts_pp(&project_facts(&parent.conclusions, left)) == facts_pp(&explicit.conclusions)
1180	}
1181	
1182	fn facts_pp(fs: &[Fact]) -> String {
1183	    fs.iter().map(pp_fact).collect::<Vec<_>>().join(", ")
1184	}
1185	
1186	fn project_facts(fs: &[Fact], left: bool) -> Vec<Fact> {
1187	    fs.iter().map(|f| project_fact(f, left)).collect()
1188	}
1189	
1190	fn project_fact(f: &Fact, left: bool) -> Fact {
1191	    Fact {
1192	        persistent: f.persistent,
1193	        name: f.name.clone(),
1194	        args: f.args.iter().map(|a| project_term(a, left)).collect(),
1195	        annotations: f.annotations.clone(),
1196	    }
1197	}
1198	
1199	/// Project a diff term to one side: `diff(a, b)` becomes `a` (left) or `b`
1200	/// (right); all other terms are structurally mapped.
1201	fn project_term(t: &Term, left: bool) -> Term {
1202	    match t {
1203	        Term::Diff(a, b) => project_term(if left { a } else { b }, left),
1204	        Term::App(name, args) => {
1205	            Term::App(name.clone(), args.iter().map(|a| project_term(a, left)).collect())
1206	        }
1207	        Term::Pair(args) => Term::Pair(args.iter().map(|a| project_term(a, left)).collect()),
1208	        Term::AlgApp(name, a, b) => Term::AlgApp(
1209	            name.clone(),
1210	            Box::new(project_term(a, left)),
1211	            Box::new(project_term(b, left)),
1212	        ),
1213	        Term::BinOp(op, a, b) => Term::BinOp(
1214	            *op,
1215	            Box::new(project_term(a, left)),
1216	            Box::new(project_term(b, left)),
1217	        ),
1218	        Term::PatMatch(inner) => Term::PatMatch(Box::new(project_term(inner, left))),
1219	        other => other.clone(),
1220	    }
1221	}
1222	
1223	// ---------------------------------------------------------------------------
1224	// 15. Lemma annotations
1225	// ---------------------------------------------------------------------------
1226	// An `exists-trace` lemma marked `reuse` is rejected (observed trigger).
1227	pub fn lemma_annotations(thy: &Theory) -> Vec<WfError> {
1228	    let mut entries: Vec<String> = Vec::new();
1229	    for it in &thy.items {
1230	        if let TheoryItem::Lemma(l) = it {
1231	            let is_reuse = l.attributes.iter().any(|a| matches!(a, LemmaAttr::Reuse));
1232	            if is_reuse && l.trace_quantifier == TraceQuantifier::ExistsTrace {
1233	                entries.push(format!(
1234	                    "  Lemma `{}': cannot reuse 'exists-trace' lemmas",
1235	                    l.name
1236	                ));
1237	            }
1238	        }
1239	    }
1240	    if entries.is_empty() {
1241	        vec![]
1242	    } else {
1243	        vec![WfError::new(T_LEMMA_ANNOT, entries.join("\n  \n"))]
1244	    }
1245	}
1246	
1247	// ---------------------------------------------------------------------------
1248	// 16. Multiplication restriction of rules
1249	// ---------------------------------------------------------------------------
1250	// A rule whose conclusions contain a multiplication (`*`) term is not
1251	// multiplication restricted. The "After replacing reducible function symbols"
1252	// rule renders identically to the original when the left-hand side has no
1253	// reducible symbols to replace (the general replacement is a documented gap).
1254	pub fn multiplication_restriction(thy: &Theory) -> Vec<WfError> {
1255	    let mut entries: Vec<String> = Vec::new();
1256	    for r in protocol_rules(thy) {
1257	        let mut mult_terms: Vec<String> = Vec::new();
1258	        for f in &r.conclusions {
1259	            for a in &f.args {
1260	                collect_mult_terms(a, &mut mult_terms);
1261	            }
1262	        }
1263	        if mult_terms.is_empty() {
1264	            continue;
1265	        }
1266	        let rule_pp = indent_block(&pp_rule(r), 4);
1267	        entries.push(format!(
1268	            "  The following rule is not multiplication restricted:\n{rule}\n  \n  After replacing reducible function symbols in lhs with variables:\n{rule}\n  \n    Terms with multiplication:  {terms}",
1269	            rule = rule_pp,
1270	            terms = mult_terms.join(", ")
1271	        ));
1272	    }
1273	    if entries.is_empty() {
1274	        vec![]
1275	    } else {
1276	        vec![WfError::new(T_MULRESTRICT, entries.join("\n  \n"))]
1277	    }
1278	}
1279	
1280	// ---------------------------------------------------------------------------
1281	// check_if_lemmas_in_theory (secondary entry point; render UNVERIFIED)
1282	// ---------------------------------------------------------------------------
1283	
1284	/// Names of every lemma-like item declared in the theory.
1285	pub fn theory_lemma_names(thy: &Theory) -> Vec<String> {
1286	    thy.items
1287	        .iter()
1288	        .filter_map(|it| match it {
1289	            TheoryItem::Lemma(l) => Some(l.name.clone()),
1290	            TheoryItem::DiffLemma(l) => Some(l.name.clone()),
1291	            TheoryItem::AccLemma(l) => Some(l.name.clone()),
1292	            _ => None,
1293	        })
1294	        .collect()
1295	}
