1	//! Term / fact pretty-printer reproducing the oracle's rendering.
2	//!
3	//! Every rule here traces to an oracle observation (see workspace/BEHAVIOR.md
4	//! and the probes t_terms, t_xor, t_nat, f_nullary).
5	
6	use crate::ast::*;
7	
8	/// Render a variable: sort prefix + base name + optional ".idx" (idx > 0).
9	pub fn pp_var(v: &VarSpec) -> String {
10	    let prefix = match v.sort {
11	        SortHint::Fresh => "~",
12	        SortHint::Pub => "$",
13	        SortHint::Nat => "%",
14	        SortHint::Node => "#",
15	        SortHint::Msg | SortHint::Untagged => "",
16	        // Suffix-sorted variables carry an explicit ":sort"; best-effort.
17	        SortHint::Suffix(_) => "",
18	    };
19	    if v.idx > 0 {
20	        format!("{}{}.{}", prefix, v.name, v.idx)
21	    } else {
22	        format!("{}{}", prefix, v.name)
23	    }
24	}
25	
26	/// Flatten a right-nested pair term into its element list.
27	fn flatten_pair(t: &Term, out: &mut Vec<String>) {
28	    match t {
29	        Term::Pair(items) => {
30	            for it in items {
31	                flatten_pair(it, out);
32	            }
33	        }
34	        Term::App(name, args) if name == "pair" && args.len() == 2 => {
35	            flatten_pair(&args[0], out);
36	            flatten_pair(&args[1], out);
37	        }
38	        other => out.push(pp_term(other)),
39	    }
40	}
41	
42	/// Collect the operands of a left/right-nested chain of the same binary op.
43	fn flatten_binop(op: BinOp, t: &Term, out: &mut Vec<Term>) {
44	    if let Term::BinOp(o, a, b) = t {
45	        if *o == op {
46	            flatten_binop(op, a, out);
47	            flatten_binop(op, b, out);
48	            return;
49	        }
50	    }
51	    out.push(t.clone());
52	}
53	
54	fn pp_binop(op: BinOp, a: &Term, b: &Term) -> String {
55	    match op {
56	        // Exponentiation is shown infix without surrounding parentheses.
57	        BinOp::Exp => format!("{}^{}", pp_term(a), pp_term(b)),
58	        // The AC operators are parenthesised and joined by their symbol.
59	        BinOp::Mult | BinOp::Union | BinOp::Xor | BinOp::NatPlus => {
60	            let sym = match op {
61	                BinOp::Mult => "*",
62	                BinOp::Union => "++",
63	                BinOp::Xor => "\u{2295}", // (+)
64	                BinOp::NatPlus => "%+",
65	                BinOp::Exp => unreachable!(),
66	            };
67	            let whole = Term::BinOp(op, Box::new(a.clone()), Box::new(b.clone()));
68	            let mut operands = Vec::new();
69	            flatten_binop(op, &whole, &mut operands);
70	            let mut parts: Vec<String> = operands.iter().map(pp_term).collect();
71	            // XOR arguments are normalised (sorted); observed in probe t_xor.
72	            if op == BinOp::Xor {
73	                parts.sort();
74	            }
75	            format!("({})", parts.join(sym))
76	        }
77	    }
78	}
79	
80	/// Render a term the way the oracle prints it inside facts.
81	pub fn pp_term(t: &Term) -> String {
82	    match t {
83	        Term::Var(v) => pp_var(v),
84	        Term::PubLit(s) => format!("'{}'", s),
85	        Term::FreshLit(s) => format!("~'{}'", s),
86	        Term::NatLit(s) => format!("%'{}'", s),
87	        Term::Number(n) => n.to_string(),
88	        Term::NumberOne => "1".to_string(),
89	        Term::NatOne => "%1".to_string(),
90	        Term::DhNeutral => "DH_neutral".to_string(),
91	        Term::App(name, args) => {
92	            if name == "pair" && args.len() == 2 {
93	                let mut elems = Vec::new();
94	                flatten_pair(t, &mut elems);
95	                format!("<{}>", elems.join(", "))
96	            } else if args.is_empty() {
97	                name.clone()
98	            } else {
99	                let parts: Vec<String> = args.iter().map(pp_term).collect();
100	                format!("{}({})", name, parts.join(", "))
101	            }
102	        }
103	        Term::AlgApp(name, a, b) => format!("{}({}, {})", name, pp_term(a), pp_term(b)),
104	        Term::Pair(_) => {
105	            let mut elems = Vec::new();
106	            flatten_pair(t, &mut elems);
107	            format!("<{}>", elems.join(", "))
108	        }
109	        Term::Diff(a, b) => format!("diff({}, {})", pp_term(a), pp_term(b)),
110	        Term::BinOp(op, a, b) => pp_binop(*op, a, b),
111	        Term::PatMatch(inner) => format!("={}", pp_term(inner)),
112	    }
113	}
114	
115	/// Render a fact: optional `!` for persistent, then `Name( args )`.
116	/// Empty argument list renders as `Name( )`.
117	pub fn pp_fact(f: &Fact) -> String {
118	    let bang = if f.persistent { "!" } else { "" };
119	    if f.args.is_empty() {
120	        format!("{}{}( )", bang, f.name)
121	    } else {
122	        let parts: Vec<String> = f.args.iter().map(pp_term).collect();
123	        format!("{}{}( {} )", bang, f.name, parts.join(", "))
124	    }
125	}
126	
127	/// Render a bracketed fact list as it appears inside a rule: `[ f1, f2 ]`, or
128	/// `[ ]` when empty.
129	pub fn pp_fact_list(fs: &[Fact]) -> String {
130	    if fs.is_empty() {
131	        "[ ]".to_string()
132	    } else {
133	        let parts: Vec<String> = fs.iter().map(pp_fact).collect();
134	        format!("[ {} ]", parts.join(", "))
135	    }
136	}
137	
138	/// Render a rule the way the oracle prints it (single-line body; the oracle
139	/// wraps very long rules across several lines - see BEHAVIOR.md gaps):
140	///
141	/// ```text
142	/// rule (modulo E) Name:
143	///    [ prems ] --> [ concls ]
144	/// ```
145	///
146	/// with `--[ acts ]->` in place of `-->` when the rule has action facts.
147	pub fn pp_rule(r: &Rule) -> String {
148	    let modulo = r.modulo.as_deref().unwrap_or("E");
149	    let prems = pp_fact_list(&r.premises);
150	    let concls = pp_fact_list(&r.conclusions);
151	    let arrow = if r.actions.is_empty() {
152	        "-->".to_string()
153	    } else {
154	        let acts: Vec<String> = r.actions.iter().map(pp_fact).collect();
155	        format!("--[ {} ]->", acts.join(", "))
156	    };
157	    format!("rule (modulo {}) {}:\n   {} {} {}", modulo, r.name, prems, arrow, concls)
158	}
