/// Returns the first quantifier whose bound variables are not all guarded,
/// together with that subformula.
fn find_unguarded(f: &Formula) -> Option<(Vec<VarSpec>, Formula)> {
    match f {
        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
            let mut gv = Vec::new();
            guard_vars(g, &mut gv);
